head.script:
// 전역 변수
scwin.memJson = $c.data.getMemInfo();
scwin.strCurDate = $c.date.getServerDateTime("yyyyMM");

scwin.onpageload = async function() {
	const codeOptions = [
        { grpCd : "ZZ205", compID : "acb_homeClsCd",opt :{"range" : "1,EQ"} },
    ];
    await $c.data.setCommonCode(codeOptions);
};

scwin.ondataload = function() { 
    acb_homeClsCd.setValue(scwin.memJson.eqHomeClsCd);   // 정비소속구분코드
    scwin.retriveWrkplList();
}

scwin.retriveWrkplList = function() {
    const params = {
        sysCd: "PsCommonEBC", 
        queryId: "retriveWrkplList",
        param1: acb_homeClsCd.getValue(),
    };

    //데이터셋에 정보설정
    dma_lc_wrkPlCd.setJSON(params);

    $c.sbm.execute(sbm_retriveWrkplList);
}

//-------------------------------------------------------------------------
// UDC 로딩 완료 후
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    ica_wrkStYm.setValue(scwin.strCurDate);
    ica_wrkEndYm.setValue(scwin.strCurDate);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    let ret = await $c.gus.cfValidate([tb_wrk]);
    if (!ret) {
        return false;
    }

    if (!$c.gus.cfIsAfterDate(ica_wrkStYm.getValue() + "01", ica_wrkEndYm.getValue() + "01")) {
        await $c.win.alert(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ica_wrkStYm.focus();
        return;
    }

    $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// 조회 조건 지우기
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tb_wrk, null);

    ica_wrkStYm.setValue(scwin.strCurDate);
    ica_wrkEndYm.setValue(scwin.strCurDate);


    // if(acb_homeClsCd.getSelectedIndex() == -1) {
    //     acb_homeClsCd.setSelectedIndex(0);
    // }

    acb_wrkPlCd.setValue(scwin.memJson.fixWrkPlCd);  // 정비작업장코드
};

//-------------------------------------------------------------------------
// 그리드 높이를 조정 : 지정된 그리드의 Height 를 size 만큼 증감 시킨다.
//-------------------------------------------------------------------------
scwin.f_GrdHeight = function(gridNm, size) {
    let strHeight = gridNm.style.height;
    let intHeight = parseInt(strHeight.replace("px", ""));
    intHeight = intHeight + size;
    if (intHeight > 0) {
        gridNm.style.height = intHeight + "px";
    }
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {
    let pWhere = "";

    switch (disGubun) {
        case 2:
            // 귀속부서 팝업			
            await udc_acctDeptCdInfo.cfCommonPopUp(scwin.udc_acctDeptCdInfo_callBackFunc,
                ed_acctDeptCd.getValue().trim(), // 화면에서의 Code Element의	Value
                ed_acctDeptNm.getValue(), // 화면에서의 Name Element의	Value
                pClose, // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                null, // 검색 결과	컬럼의 보여주는	개수
                null, // Title순서	
                null, // 보여주는 각 컬럼들의 폭	
                null, // 컬럼중에서 숨기는	컬럼 지정	
                pWhere, // SQL절의 WHERE절에	원하는 조건을 선택함
                null, // POP-UP뛰을때 원도우의	사용자 정의	폭
                null, // POP-UP뛰을때 우도우의	사용자 정의	높이	
                null, // 윈도우 위치 Y좌표	
                null, // 윈도우 위치 X좌표
                null, // 중복체크여부	("F")
                "T", // 전체검색허용여부	("F")
                "귀속부서,부서코드,부서명" // POP-UP Window Title
            );
            break;
    }
};

scwin.udc_acctDeptCdInfo_callBackFunc = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_acctDeptCd.setValue(rtnList[0]);
        ed_acctDeptNm.setValue(rtnList[1]);
    } else {
        ed_acctDeptCd.setValue("");
        ed_acctDeptNm.setValue("");
    }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    $c.gus.cfClearPairObj(pairObj);
    let pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// 엑셀 출력
//-------------------------------------------------------------------------
scwin.f_Excel = async function() {
    if (!(ds_fix_fee_list.getRowCount() > 0)) {
        await $c.win.alert("자료가 없습니다.");
        return;
    }

    let gridColCount = gr_work_pl.getTotalCol();
    let startRowIndex = 0; 
    let homeClsCd = acb_homeClsCd.getText();
    if(homeClsCd == null) {
        homeClsCd = "";
    } else {
        homeClsCd = acb_homeClsCd.getText();
    }
    let infoArr = [{
        rowIndex : 0,             // 첫 번째 줄
        colIndex : 0,             // 첫 번째 칸부터
        colSpan : gridColCount,   // 그리드 전체 너비만큼 병합
        rowSpan : 1,
        text : "엔진형식별정비비 조회",
        textAlign : "center",     // 정렬
        fontSize : 12,
        drawBorder : false,        // 테두리
        color : "black",          // 글자색
        backgroundColor : "white" // 배경색
    },{
        rowIndex : 2,             // 첫 번째 줄
        colIndex : 0,             // 첫 번째 칸부터
        colSpan : gridColCount,   // 그리드 전체 너비만큼 병합
        rowSpan : 1,
        text : "정비기간 ["+$c.gus.cfGetFormatStr(ica_wrkStYm.getValue(), "####/##") + " ~ " + $c.gus.cfGetFormatStr(ica_wrkEndYm.getValue(), "####/##")+"]",
        textAlign : "left",     // 정렬
        fontSize : 10,
        drawBorder : false,        // 테두리
        color : "black",          // 글자색
        backgroundColor : "white" // 배경색
    },{
        rowIndex : 3,             // 첫 번째 줄
        colIndex : 0,             // 첫 번째 칸부터
        colSpan : gridColCount,   // 그리드 전체 너비만큼 병합
        rowSpan : 1,
        text : "사업부문 ["+homeClsCd+"]",
        textAlign : "left",     // 정렬
        fontSize : 10, 
        drawBorder : false,        // 테두리
        color : "black",          // 글자색
        backgroundColor : "white" // 배경색
    },{
        rowIndex : 4,             // 첫 번째 줄
        colIndex : 0,             // 첫 번째 칸부터
        colSpan : gridColCount,   // 그리드 전체 너비만큼 병합
        rowSpan : 1,
        text : "정비작업장 ["+acb_wrkPlCd.getText()+"]",
        textAlign : "left",     // 정렬
        fontSize : 10, 
        drawBorder : false,        // 테두리
        color : "black",          // 글자색
        backgroundColor : "white" // 배경색
    }];

    if ( ed_acctDeptCd.getValue().trim() != "" ) {
        infoArr.push({
            rowIndex : 5,             // 첫 번째 줄
            colIndex : 0,             // 첫 번째 칸부터
            colSpan : gridColCount,   // 그리드 전체 너비만큼 병합
            rowSpan : 1,
            text : "귀속부서 ["+ed_acctDeptCd.getValue()+ "-" + ed_acctDeptNm.getValue()+"]",
            textAlign : "left",     // 정렬
            fontSize : 10,
            drawBorder : false,        // 테두리
            color : "black",          // 글자색
            backgroundColor : "white" // 배경색
        })

        startRowIndex=6;
    } else {
        startRowIndex=5;
    }

    const options = {
        fileName: "엔진형식별정비비 조회.xlsx",
        sheetName: "엔진형식별정비비 조회",
        startRowIndex : startRowIndex,        
        startColumnIndex : 0,
        columnMove:true,
        columnMoveWithFooter:true,
        type : 1
    };
    $c.data.downloadGridViewExcel(gr_work_pl, options,infoArr);
};

scwin.sbm_retrieve_submitdone = function (e) {
    totalRows.setValue(ds_fix_fee_list.getRowCount());
};

scwin.sbm_retriveWrkplList_submitdone = function (e) {
    acb_wrkPlCd.setValue(scwin.memJson.fixWrkPlCd); // 정비작업장코드

    if(acb_wrkPlCd.getSelectedIndex() == -1) {
        acb_wrkPlCd.setSelectedIndex(0);
    }
};

scwin.acb_homeClsCd_onchange = function (info) {
    scwin.retriveWrkplList();
};

scwin.udc_acctDeptCdInfo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_acctDeptCd, ed_acctDeptNm, 2, false);
};

scwin.udc_acctDeptCdInfo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_acctDeptNm, ed_acctDeptCd, 2, false);
};

scwin.udc_acctDeptCdInfo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_acctDeptCd.getValue(), ed_acctDeptNm.getValue(),'F','T');
};

scwin.btn_clear_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};
